// Package model contains domain models for statistics functionality.
package model

import "errors"

// Checklist item errors.
var (
	// ErrChecklistItemNotFound is returned when a checklist item is not found.
	ErrChecklistItemNotFound = errors.New("checklist item not found")

	// ErrDuplicateChecklistItemID is returned when trying to create an item with an existing ID.
	ErrDuplicateChecklistItemID = errors.New("checklist item id already exists")

	// ErrInvalidCategory is returned when an invalid category is provided.
	ErrInvalidCategory = errors.New("invalid category")

	// ErrEmptyChecklistItemID is returned when an empty item ID is provided.
	ErrEmptyChecklistItemID = errors.New("checklist item id cannot be empty")

	// ErrEmptyChecklistItemLabel is returned when an empty item label is provided.
	ErrEmptyChecklistItemLabel = errors.New("checklist item label cannot be empty")
)

// Maturity level errors.
var (
	// ErrInvalidMaturityLevel is returned when an invalid maturity level is provided.
	ErrInvalidMaturityLevel = errors.New("maturity level must be between 1 and 5")

	// ErrMaturityLevelNotFound is returned when no maturity level record exists.
	ErrMaturityLevelNotFound = errors.New("maturity level not found")
)

// ValidCategories defines the valid category values.
var ValidCategories = []string{
	"governance",
	"training",
	"knowledge",
	"technology",
	"process",
}

// IsValidCategory checks if the given category is valid.
func IsValidCategory(category string) bool {
	for _, c := range ValidCategories {
		if c == category {
			return true
		}
	}
	return false
}

// MinMaturityLevel is the minimum valid maturity level.
const MinMaturityLevel = 1

// MaxMaturityLevel is the maximum valid maturity level.
const MaxMaturityLevel = 5

// IsValidMaturityLevel checks if the given level is valid.
func IsValidMaturityLevel(level int) bool {
	return level >= MinMaturityLevel && level <= MaxMaturityLevel
}

