// Package apperror provides structured error handling for the application.
// It uses github.com/newmo-oss/ergo for error wrapping with attributes and stack traces.
package apperror

import (
	"errors"
	"net/http"

	"github.com/newmo-oss/ergo"
)

// CodedError links a sentinel error with an HTTP status code and default message.
// It implements the error interface and can be used with errors.Is() for error matching.
type CodedError struct {
	sentinel   error  // Sentinel error created by ergo.NewSentinel()
	code       string // Error code string (e.g., "STAT001")
	message    string // Default message for HTTP response
	httpStatus int    // HTTP status code
}

// Error returns the error message.
func (e *CodedError) Error() string {
	return e.message
}

// Unwrap returns the sentinel error for use with errors.Is().
func (e *CodedError) Unwrap() error {
	return e.sentinel
}

// Code returns the error code string.
func (e *CodedError) Code() string {
	return e.code
}

// HTTPStatus returns the HTTP status code.
func (e *CodedError) HTTPStatus() int {
	return e.httpStatus
}

// Sentinel returns the underlying sentinel error.
func (e *CodedError) Sentinel() error {
	return e.sentinel
}

// Is implements the errors.Is interface for error matching.
func (e *CodedError) Is(target error) bool {
	if target == nil {
		return false
	}
	// Match against sentinel
	if errors.Is(e.sentinel, target) {
		return true
	}
	// Match against another CodedError
	var coded *CodedError
	if errors.As(target, &coded) {
		return e.code == coded.code
	}
	return false
}

// newCodedError creates a new CodedError with the given parameters.
func newCodedError(code, message string, httpStatus int) *CodedError {
	return &CodedError{
		sentinel:   ergo.NewSentinel(message),
		code:       code,
		message:    message,
		httpStatus: httpStatus,
	}
}

// Statistics API Errors (STAT001-007).
var (
	// ErrStatPeriodInvalid is returned when the period format is invalid.
	ErrStatPeriodInvalid = newCodedError("STAT001", "invalid period format", http.StatusBadRequest)

	// ErrStatPeriodOutOfRange is returned when the period is out of allowed range.
	ErrStatPeriodOutOfRange = newCodedError("STAT002", "period out of range", http.StatusBadRequest)

	// ErrStatDataNotFound is returned when statistics data is not found.
	ErrStatDataNotFound = newCodedError("STAT003", "statistics data not found", http.StatusNotFound)

	// ErrStatAggregationFailed is returned when data aggregation fails.
	ErrStatAggregationFailed = newCodedError("STAT004", "aggregation failed", http.StatusInternalServerError)

	// ErrStatDatabaseError is returned when a database error occurs in statistics.
	ErrStatDatabaseError = newCodedError("STAT005", "database error", http.StatusInternalServerError)

	// ErrStatInvalidWeeks is returned when the weeks parameter is invalid (must be 1-52).
	ErrStatInvalidWeeks = newCodedError("STAT006", "weeks must be between 1 and 52", http.StatusBadRequest)

	// ErrStatInvalidRiskLevel is returned when the riskLevel parameter is invalid.
	ErrStatInvalidRiskLevel = newCodedError("STAT007", "risk level must be one of: high, medium, low", http.StatusBadRequest)
)

// Authentication Errors (AUTH001-003).
var (
	// ErrAuthRequired is returned when authentication is required but not provided.
	ErrAuthRequired = newCodedError("AUTH001", "authentication required", http.StatusUnauthorized)

	// ErrAuthAccessDenied is returned when access is denied due to insufficient permissions.
	ErrAuthAccessDenied = newCodedError("AUTH002", "access denied", http.StatusForbidden)

	// ErrAuthTokenInvalid is returned when the authentication token is invalid or expired.
	ErrAuthTokenInvalid = newCodedError("AUTH003", "invalid or expired token", http.StatusUnauthorized)
)

// General Errors (GEN001-003).
var (
	// ErrGenNotFound is returned when a requested resource is not found.
	ErrGenNotFound = newCodedError("GEN001", "resource not found", http.StatusNotFound)

	// ErrGenInternalError is returned for unexpected internal errors.
	ErrGenInternalError = newCodedError("GEN002", "internal server error", http.StatusInternalServerError)

	// ErrGenValidation is returned when request validation fails.
	ErrGenValidation = newCodedError("GEN003", "validation error", http.StatusBadRequest)
)

// Process Errors (PROC001-003).
var (
	// ErrProcDuplicate is returned when a process name already exists in the department.
	ErrProcDuplicate = newCodedError("PROC001", "process name already exists in this department", http.StatusConflict)

	// ErrProcNotFound is returned when a process is not found.
	ErrProcNotFound = newCodedError("PROC002", "process not found", http.StatusNotFound)

	// ErrProcDepartmentNotFound is returned when the department for a process is not found.
	ErrProcDepartmentNotFound = newCodedError("PROC003", "department not found", http.StatusNotFound)
)

// Process Step Errors (STEP001-004).
var (
	// ErrStepDuplicate is returned when a step name already exists in the process.
	ErrStepDuplicate = newCodedError("STEP001", "step name already exists in this process", http.StatusConflict)

	// ErrStepNotFound is returned when a step is not found.
	ErrStepNotFound = newCodedError("STEP002", "step not found", http.StatusNotFound)

	// ErrStepProcessNotFound is returned when the process for a step is not found.
	ErrStepProcessNotFound = newCodedError("STEP003", "process not found", http.StatusNotFound)

	// ErrStepInvalidImportance is returned when the importance value is invalid.
	ErrStepInvalidImportance = newCodedError("STEP004", "importance must be between 1 and 3", http.StatusBadRequest)
)

// allCodedErrors contains all defined CodedError instances for lookup.
var allCodedErrors = []*CodedError{
	// Statistics errors
	ErrStatPeriodInvalid,
	ErrStatPeriodOutOfRange,
	ErrStatDataNotFound,
	ErrStatAggregationFailed,
	ErrStatDatabaseError,
	ErrStatInvalidWeeks,
	ErrStatInvalidRiskLevel,
	// Authentication errors
	ErrAuthRequired,
	ErrAuthAccessDenied,
	ErrAuthTokenInvalid,
	// General errors
	ErrGenNotFound,
	ErrGenInternalError,
	ErrGenValidation,
	// Process errors
	ErrProcDuplicate,
	ErrProcNotFound,
	ErrProcDepartmentNotFound,
	// Process step errors
	ErrStepDuplicate,
	ErrStepNotFound,
	ErrStepProcessNotFound,
	ErrStepInvalidImportance,
}

// findCodedErrorByCode searches for a CodedError by its code string.
// Returns ErrGenInternalError if the code is not found.
func findCodedErrorByCode(code string) *CodedError {
	for _, coded := range allCodedErrors {
		if coded.code == code {
			return coded
		}
	}
	return ErrGenInternalError
}

package apperror

import (
	"errors"
	"log/slog"

	"github.com/gin-gonic/gin"
	"github.com/newmo-oss/ergo"
	"github.com/newmo-oss/go-caller"
)

// attrKeyCode is the attribute key for error codes.
const attrKeyCode = "code"

// StackFrame represents a single frame in a stack trace.
type StackFrame struct {
	File     string `json:"file"`
	Line     int    `json:"line"`
	Function string `json:"function"`
}

// Handle processes an error and sends an appropriate HTTP response.
// It extracts the error code, determines the HTTP status, logs the error,
// and returns a structured JSON response.
func Handle(c *gin.Context, err error) {
	// 1. Extract code from error attributes
	code := extractCodeFromError(err)

	// 2. Find CodedError to get status and message
	coded := findCodedErrorByCode(code)
	status := determineHTTPStatus(err, code)

	// 3. Extract details from error attributes
	details := extractDetailsFromError(err)

	// 4. Log the error
	logError(code, err)

	// 5. Send HTTP response with CodedError's default message
	c.AbortWithStatusJSON(status, ErrorResponse{
		Error: ErrorBody{
			Code:    code,
			Message: coded.message,
			Details: details,
		},
	})
}

// extractCodeFromError extracts the "code" attribute from an ergo error.
// Returns "GEN002" if no code attribute is found.
func extractCodeFromError(err error) string {
	for attr := range ergo.AttrsAll(err) {
		if attr.Key == attrKeyCode {
			return attr.Value.String()
		}
	}
	return ErrGenInternalError.code
}

// determineHTTPStatus determines the HTTP status code for an error.
// First tries sentinel matching with errors.Is, then falls back to code lookup.
func determineHTTPStatus(err error, code string) int {
	// Try sentinel matching first
	for _, coded := range allCodedErrors {
		if errors.Is(err, coded.sentinel) {
			return coded.httpStatus
		}
	}

	// Fall back to code lookup
	return findCodedErrorByCode(code).httpStatus
}

// extractDetailsFromError extracts all attributes except "code" from an ergo error.
// Returns nil if no details are found.
func extractDetailsFromError(err error) any {
	details := make(map[string]any)

	for attr := range ergo.AttrsAll(err) {
		if attr.Key != attrKeyCode {
			details[attr.Key] = attrToInterface(attr.Value)
		}
	}

	if len(details) == 0 {
		return nil
	}
	return details
}

// attrToInterface converts a slog.Value to an interface{}.
func attrToInterface(v slog.Value) any {
	switch v.Kind() {
	case slog.KindString:
		return v.String()
	case slog.KindInt64:
		return v.Int64()
	case slog.KindUint64:
		return v.Uint64()
	case slog.KindFloat64:
		return v.Float64()
	case slog.KindBool:
		return v.Bool()
	case slog.KindDuration:
		return v.Duration().String()
	case slog.KindTime:
		return v.Time().Format("2006-01-02T15:04:05Z07:00")
	case slog.KindAny:
		return v.Any()
	case slog.KindGroup:
		group := make(map[string]any)
		for _, attr := range v.Group() {
			group[attr.Key] = attrToInterface(attr.Value)
		}
		return group
	case slog.KindLogValuer:
		// Resolve LogValuer to its underlying value
		return attrToInterface(v.Resolve())
	default:
		return v.String()
	}
}

// logError logs the error with structured information.
// This function is not tested directly; only HTTP response is tested.
func logError(code string, err error) {
	attrs := []any{
		slog.String(attrKeyCode, code),
		slog.String("message", err.Error()),
	}

	// Add stack trace as structured array
	if frames := ergo.StackTraceOf(err); frames != nil {
		stackFrames := formatStackTraceAsArray(frames)
		attrs = append(attrs, slog.Any("stack", stackFrames))
	}

	// Add all error attributes
	for attr := range ergo.AttrsAll(err) {
		if attr.Key != attrKeyCode {
			attrs = append(attrs, slog.Any(attr.Key, attrToInterface(attr.Value)))
		}
	}

	slog.Error("error occurred", attrs...)
}

// formatStackTraceAsArray converts caller.StackTrace to a slice of StackFrame.
func formatStackTraceAsArray(frames caller.StackTrace) []StackFrame {
	result := make([]StackFrame, 0, len(frames))

	for _, frame := range frames {
		result = append(result, StackFrame{
			File:     frame.File(),
			Line:     frame.Line(),
			Function: frame.FuncName(),
		})
	}

	return result
}

// Package model contains domain models for the users bulk import module.
package model

import (
	"time"

	"github.com/google/uuid"
)

// ImportJobStatus represents the status of an import job.
type ImportJobStatus string

const (
	// ImportJobStatusPending indicates the job is waiting to be processed.
	ImportJobStatusPending ImportJobStatus = "pending"
	// ImportJobStatusProcessing indicates the job is currently being processed.
	ImportJobStatusProcessing ImportJobStatus = "processing"
	// ImportJobStatusCompleted indicates the job has completed successfully.
	ImportJobStatusCompleted ImportJobStatus = "completed"
	// ImportJobStatusFailed indicates the job has failed.
	ImportJobStatusFailed ImportJobStatus = "failed"
)

const (
	// percentMultiplier is used for percentage calculation.
	percentMultiplier = 100
)

// String returns the string representation of the status.
func (s ImportJobStatus) String() string {
	return string(s)
}

// IsValid checks if the status is valid.
func (s ImportJobStatus) IsValid() bool {
	switch s {
	case ImportJobStatusPending, ImportJobStatusProcessing, ImportJobStatusCompleted, ImportJobStatusFailed:
		return true
	default:
		return false
	}
}

// ImportJob represents a bulk user import job.
type ImportJob struct {
	ID             string
	Status         ImportJobStatus
	TotalCount     int
	ProcessedCount int
	SuccessCount   int
	FailedCount    int
	CSVData        string
	WebhookURL     *string
	Result         *ImportJobResult
	ErrorMessage   *string
	StartedAt      *time.Time
	CompletedAt    *time.Time
	CreatedAt      time.Time
	UpdatedAt      time.Time
}

// ImportJobResult contains the result of an import job.
type ImportJobResult struct {
	Failures []ImportFailure `json:"failures"`
}

// ImportFailure represents a single import failure.
type ImportFailure struct {
	Row   int    `json:"row"`
	Email string `json:"email"`
	Error string `json:"error"`
}

// NewImportJob creates a new ImportJob entity.
func NewImportJob(csvData string, webhookURL *string) *ImportJob {
	now := time.Now()
	return &ImportJob{
		ID:             uuid.New().String(),
		Status:         ImportJobStatusPending,
		TotalCount:     0,
		ProcessedCount: 0,
		SuccessCount:   0,
		FailedCount:    0,
		CSVData:        csvData,
		WebhookURL:     webhookURL,
		Result:         nil,
		ErrorMessage:   nil,
		StartedAt:      nil,
		CompletedAt:    nil,
		CreatedAt:      now,
		UpdatedAt:      now,
	}
}

// ReconstructImportJob reconstructs an ImportJob entity from persistence.
func ReconstructImportJob(
	id string,
	status ImportJobStatus,
	totalCount, processedCount, successCount, failedCount int,
	csvData string,
	webhookURL *string,
	result *ImportJobResult,
	errorMessage *string,
	startedAt, completedAt *time.Time,
	createdAt, updatedAt time.Time,
) *ImportJob {
	return &ImportJob{
		ID:             id,
		Status:         status,
		TotalCount:     totalCount,
		ProcessedCount: processedCount,
		SuccessCount:   successCount,
		FailedCount:    failedCount,
		CSVData:        csvData,
		WebhookURL:     webhookURL,
		Result:         result,
		ErrorMessage:   errorMessage,
		StartedAt:      startedAt,
		CompletedAt:    completedAt,
		CreatedAt:      createdAt,
		UpdatedAt:      updatedAt,
	}
}

// Start marks the job as processing.
func (j *ImportJob) Start(totalCount int) {
	now := time.Now()
	j.Status = ImportJobStatusProcessing
	j.TotalCount = totalCount
	j.StartedAt = &now
	j.UpdatedAt = now
}

// UpdateProgress updates the job progress.
func (j *ImportJob) UpdateProgress(processedCount, successCount, failedCount int) {
	j.ProcessedCount = processedCount
	j.SuccessCount = successCount
	j.FailedCount = failedCount
	j.UpdatedAt = time.Now()
}

// Complete marks the job as completed.
func (j *ImportJob) Complete(result *ImportJobResult) {
	now := time.Now()
	j.Status = ImportJobStatusCompleted
	j.Result = result
	j.CompletedAt = &now
	j.UpdatedAt = now
}

// Fail marks the job as failed.
func (j *ImportJob) Fail(errorMessage string) {
	now := time.Now()
	j.Status = ImportJobStatusFailed
	j.ErrorMessage = &errorMessage
	j.CompletedAt = &now
	j.UpdatedAt = now
}

// ProgressPercent returns the progress percentage.
func (j *ImportJob) ProgressPercent() int {
	if j.TotalCount == 0 {
		return 0
	}
	return (j.ProcessedCount * percentMultiplier) / j.TotalCount
}

// IsFinished returns true if the job has finished (completed or failed).
func (j *ImportJob) IsFinished() bool {
	return j.Status == ImportJobStatusCompleted || j.Status == ImportJobStatusFailed
}

// IsPending returns true if the job is pending.
func (j *ImportJob) IsPending() bool {
	return j.Status == ImportJobStatusPending
}

// IsProcessing returns true if the job is processing.
func (j *ImportJob) IsProcessing() bool {
	return j.Status == ImportJobStatusProcessing
}

