// Package usecase implements use case interactors for the users module.
package usecase

import (
	"context"
	"fmt"
	"log/slog"
	"net/url"
	"strings"

	"github.com/secure-cycle/ai-monitoring-backend-go/internal/users/domain/model"
	"github.com/secure-cycle/ai-monitoring-backend-go/internal/users/domain/repository"
	"github.com/secure-cycle/ai-monitoring-backend-go/internal/users/usecase/port/input"
)

// CreateImportJobInteractor implements the CreateImportJobInput interface.
type CreateImportJobInteractor struct {
	jobRepo   repository.ImportJobRepository
	csvParser repository.CSVParser
	logger    *slog.Logger
	baseURL   string
}

// Ensure CreateImportJobInteractor implements the interface at compile time.
var _ input.CreateImportJobInput = (*CreateImportJobInteractor)(nil)

// NewCreateImportJobInteractor creates a new CreateImportJobInteractor.
func NewCreateImportJobInteractor(
	jobRepo repository.ImportJobRepository,
	csvParser repository.CSVParser,
	logger *slog.Logger,
	baseURL string,
) *CreateImportJobInteractor {
	return &CreateImportJobInteractor{
		jobRepo:   jobRepo,
		csvParser: csvParser,
		logger:    logger,
		baseURL:   baseURL,
	}
}

// Execute creates a new import job.
func (i *CreateImportJobInteractor) Execute(ctx context.Context, req *input.CreateImportJobRequest) (*input.CreateImportJobResponse, error) {
	// Validate webhook URL if provided
	if req.WebhookURL != nil && *req.WebhookURL != "" {
		if err := i.validateWebhookURL(*req.WebhookURL); err != nil {
			return nil, err
		}
	}

	// Validate CSV format (parse to check structure)
	parseResult, err := i.csvParser.Parse(strings.NewReader(req.CSVData))
	if err != nil {
		i.logger.ErrorContext(ctx, "Failed to parse CSV",
			slog.String("error", err.Error()))
		return nil, err
	}

	// Check if there are any valid rows
	if len(parseResult.Rows) == 0 && len(parseResult.ParseErrors) == 0 {
		return nil, model.ErrInvalidCSVFormat
	}

	// Check for concurrent job execution
	exists, err := i.jobRepo.ExistsPendingOrProcessing(ctx)
	if err != nil {
		i.logger.ErrorContext(ctx, "Failed to check for concurrent jobs",
			slog.String("error", err.Error()))
		return nil, fmt.Errorf("failed to check for concurrent jobs: %w", err)
	}
	if exists {
		return nil, model.ErrJobAlreadyRunning
	}

	// Create import job
	var webhookURL *string
	if req.WebhookURL != nil && *req.WebhookURL != "" {
		webhookURL = req.WebhookURL
	}

	job := model.NewImportJob(req.CSVData, webhookURL)

	if err := i.jobRepo.Create(ctx, job); err != nil {
		i.logger.ErrorContext(ctx, "Failed to create import job",
			slog.String("error", err.Error()))
		return nil, fmt.Errorf("failed to create import job: %w", err)
	}

	i.logger.InfoContext(ctx, "Created import job",
		slog.String("job_id", job.ID))

	return &input.CreateImportJobResponse{
		JobID:     job.ID,
		Status:    string(job.Status),
		CreatedAt: job.CreatedAt.Format("2006-01-02T15:04:05Z"),
		StatusURL: fmt.Sprintf("%s/v1/users/bulk-import/%s", i.baseURL, job.ID),
	}, nil
}

// validateWebhookURL validates that the webhook URL is HTTPS.
func (i *CreateImportJobInteractor) validateWebhookURL(webhookURL string) error {
	parsed, err := url.Parse(webhookURL)
	if err != nil {
		return model.ErrWebhookURLInvalid
	}
	if !strings.EqualFold(parsed.Scheme, "https") {
		return model.ErrWebhookURLInvalid
	}
	return nil
}

