// Package handler provides HTTP request handlers for the users REST API interface layer.
package handler

import (
	"io"
	"log/slog"
	"net/http"
	"strconv"

	"github.com/gin-gonic/gin"

	"github.com/secure-cycle/ai-monitoring-backend-go/internal/users/domain/model"
