)

const (
	// MaxFileSize is the maximum allowed file size (5MB).
	MaxFileSize = 5 * 1024 * 1024
)

// ImportJobHandler handles HTTP requests for bulk user import operations.
type ImportJobHandler struct {
	createJobUseCase input.CreateImportJobInput
	getJobUseCase    input.GetImportJobInput
	listJobsUseCase  input.ListImportJobsInput
	logger           *slog.Logger
}

// NewImportJobHandler creates a new ImportJobHandler instance.
func NewImportJobHandler(
	createJobUseCase input.CreateImportJobInput,
	getJobUseCase input.GetImportJobInput,
	listJobsUseCase input.ListImportJobsInput,
) *ImportJobHandler {
	return &ImportJobHandler{
		createJobUseCase: createJobUseCase,
		getJobUseCase:    getJobUseCase,
		listJobsUseCase:  listJobsUseCase,
		logger:           slog.Default(),
	}
}

// CreateImportJob handles POST /v1/users/bulk-import requests.
func (h *ImportJobHandler) CreateImportJob(c *gin.Context) {
	// Get file from multipart form
	file, header, err := c.Request.FormFile("file")
	if err != nil {
		h.respondError(c, http.StatusBadRequest, "MISSING_FILE", "CSVファイルが必要です")
		return
	}
	defer func() {
		if err := file.Close(); err != nil {
			h.logger.WarnContext(c.Request.Context(), "Failed to close uploaded file", slog.String("error", err.Error()))
		}
	}()

	// Check file size
	if header.Size > MaxFileSize {
		h.respondError(c, http.StatusBadRequest, "FILE_TOO_LARGE", "ファイルサイズは最大5MBです")
		return
	}

	// Read file content
	csvData, err := io.ReadAll(file)
	if err != nil {
		h.logger.ErrorContext(c.Request.Context(), "Failed to read file",
			slog.String("error", err.Error()))
		h.respondError(c, http.StatusInternalServerError, "INTERNAL_ERROR", "ファイルの読み取りに失敗しました")
		return
	}

	// Get optional webhook URL
	var webhookURL *string
	if url := c.PostForm("webhook_url"); url != "" {
		webhookURL = &url
	}

	// Create import job
	req := &input.CreateImportJobRequest{
		CSVData:    string(csvData),
		WebhookURL: webhookURL,
	}

	resp, err := h.createJobUseCase.Execute(c.Request.Context(), req)
	if err != nil {
		h.handleError(c, err)
		return
	}

	c.JSON(http.StatusAccepted, mapper.ToCreateImportJobResponse(resp))
}

// GetImportJob handles GET /v1/users/bulk-import/:job_id requests.
func (h *ImportJobHandler) GetImportJob(c *gin.Context) {
	jobID := c.Param("job_id")
	if jobID == "" {
		h.respondError(c, http.StatusBadRequest, "MISSING_JOB_ID", "ジョブIDが必要です")
		return
	}

	job, err := h.getJobUseCase.Execute(c.Request.Context(), jobID)
	if err != nil {
		h.handleError(c, err)
		return
	}

	c.JSON(http.StatusOK, mapper.ToImportJobResponse(job))
}

// ListImportJobs handles GET /v1/users/bulk-import requests.
func (h *ImportJobHandler) ListImportJobs(c *gin.Context) {
	// Parse pagination parameters
	limit, _ := strconv.Atoi(c.DefaultQuery("limit", "20"))
