		h.handleError(c, err)
		return
	}

	c.JSON(http.StatusOK, mapper.ToListImportJobsResponse(resp))
}

// handleError handles domain errors and responds with appropriate HTTP status codes.
func (h *ImportJobHandler) handleError(c *gin.Context, err error) {
	switch err {
	case model.ErrJobNotFound:
		h.respondError(c, http.StatusNotFound, "JOB_NOT_FOUND", "指定されたジョブが見つかりません")
	case model.ErrJobAlreadyRunning:
		h.respondError(c, http.StatusConflict, "JOB_ALREADY_RUNNING", "別のインポートジョブが実行中です。完了後に再度お試しください。")
	case model.ErrInvalidCSVFormat:
		h.respondError(c, http.StatusBadRequest, "INVALID_CSV_FORMAT", "CSVの形式が不正です")
	case model.ErrMissingRequiredColumns:
		h.respondError(c, http.StatusBadRequest, "MISSING_REQUIRED_COLUMNS", "必須カラムが不足しています")
	case model.ErrInvalidUTF8Encoding:
		h.respondError(c, http.StatusBadRequest, "INVALID_ENCODING", "CSVはUTF-8エンコーディングである必要があります")
	case model.ErrWebhookURLInvalid:
		h.respondError(c, http.StatusBadRequest, "INVALID_WEBHOOK_URL", "Webhook URLはHTTPSである必要があります")
	default:
		h.logger.ErrorContext(c.Request.Context(), "Internal error",
			slog.String("error", err.Error()))
		h.respondError(c, http.StatusInternalServerError, "INTERNAL_ERROR", "内部エラーが発生しました")
	}
}

